def classify_status(status: int) -> str:
    """Map an HTTP status code to an agent action category."""
    if status == 429:
        return "rate_limit"       # retryable — wait for Retry-After
    if status in (500, 502, 503, 504):
        return "transient"        # retryable — server-side fault
    if status == 401:
        return "auth_invalid"     # fix credentials, do not retry
    if status == 403:
        return "auth_forbidden"   # fix permissions, do not retry
    if status == 404:
        return "not_found"        # resource missing, do not retry
    if 400 <= status < 500:
        return "client_error"     # bad request, do not retry
    if 200 <= status < 300:
        return "ok"
    return "unknown"

import time
import random
import httpx

class AgentHTTPClient:
    """HTTP client with status-code-aware retry logic for agent tool calls."""

    RETRYABLE_STATUS = {429, 500, 502, 503, 504}
    MAX_RETRIES = 5
    BASE_DELAY_S = 1.0

    def __init__(self, base_url: str, api_key: str) -> None:
        self._client = httpx.Client(
            base_url=base_url,
            headers={
                "Authorization": f"Bearer {api_key}",
                "Content-Type": "application/json",
                "Accept": "application/json",
            },
            timeout=httpx.Timeout(connect=5.0, read=120.0, write=30.0, pool=5.0),
        )

    def post(
        self,
        path: str,
        body: dict,
        idempotency_key: str | None = None,
    ) -> dict:
        headers = {}
        if idempotency_key:
            headers["Idempotency-Key"] = idempotency_key
        return self._request("POST", path, json=body, extra_headers=headers)

    def get(self, path: str, params: dict | None = None) -> dict:
        return self._request("GET", path, params=params)

    def delete(self, path: str) -> None:
        self._request("DELETE", path)

    def _request(self, method: str, path: str, **kwargs) -> dict:
        extra_headers = kwargs.pop("extra_headers", {})
        for attempt in range(self.MAX_RETRIES):
            resp = self._client.request(
                method, path, headers=extra_headers, **kwargs
            )

            if resp.status_code in self.RETRYABLE_STATUS:
                if attempt == self.MAX_RETRIES - 1:
                    resp.raise_for_status()
                time.sleep(self._backoff(resp, attempt))
                continue

            if resp.status_code == 401:
                raise PermissionError("Invalid API key — check credentials")
            if resp.status_code == 403:
                raise PermissionError("Forbidden — insufficient permissions")
            if 400 <= resp.status_code < 500:
                raise ValueError(f"Client error {resp.status_code}: {resp.text}")

            resp.raise_for_status()
            if resp.status_code == 204:
                return {}  # success with no body
            return resp.json()

        raise RuntimeError("Max retries exceeded")

    def _backoff(self, resp: httpx.Response, attempt: int) -> float:
        """Prefer Retry-After header; fall back to exponential backoff."""
        if resp.status_code == 429:
            retry_after = resp.headers.get("Retry-After", "")
            if retry_after.isdigit():
                return float(retry_after)
        jitter = random.uniform(0, 0.5)
        return self.BASE_DELAY_S * (2 ** attempt) + jitter

    def close(self) -> None:
        self._client.close()

import httpx

def call_llm(prompt: str, api_key: str) -> str:
    """Minimal LLM call with correct status-code handling."""
    with httpx.Client(timeout=60.0) as client:
        resp = client.post(
            "https://api.openai.com/v1/chat/completions",
            headers={
                "Authorization": f"Bearer {api_key}",
                "Content-Type": "application/json",
            },
            json={
                "model": "gpt-4o-mini",
                "messages": [{"role": "user", "content": prompt}],
            },
        )

    if resp.status_code == 200:
        return resp.json()["choices"][0]["message"]["content"]

    if resp.status_code == 429:
        retry_after = int(resp.headers.get("Retry-After", "5"))
        raise RuntimeError(f"Rate limited. Retry after {retry_after}s")

    if resp.status_code == 401:
        raise PermissionError("Invalid API key")

    resp.raise_for_status()  # raises HTTPStatusError for other 4xx/5xx
    return ""  # unreachable, satisfies type checker

