// Idempotent POST: safe to retry because Idempotency-Key is attached.
async function invokeToolSafely(toolName, params, runId) {
  const MAX_RETRIES = 4;
  let delay = 1000; // ms

  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    const response = await fetch(`https://tools.example.com/invoke/${toolName}`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${process.env.TOOLS_API_KEY}`,
        // Unique per logical operation — server deduplicates on retry
        "Idempotency-Key": `${runId}::${toolName}`,
      },
      body: JSON.stringify(params),
    });

    // 2xx — success
    if (response.ok) {
      if (response.status === 204) return null; // No Content: do NOT call .json()
      return await response.json();
    }

    // Retryable: rate limited or transient server error
    if (response.status === 429 || response.status >= 500) {
      if (attempt === MAX_RETRIES) {
        throw new Error(`Tool call failed after ${MAX_RETRIES} retries: HTTP ${response.status}`);
      }
      const retryAfter = response.headers.get("Retry-After");
      const waitMs = retryAfter ? parseInt(retryAfter, 10) * 1000 : delay;
      await new Promise(r => setTimeout(r, waitMs));
      delay = Math.min(delay * 2, 30_000); // cap at 30 s
      continue;
    }

    // Non-retryable 4xx
    const body = await response.text();
    throw new Error(`HTTP ${response.status}: ${body}`);
  }
}

import time
import httpx

def call_anthropic_messages(
    messages: list[dict],
    api_key: str,
    model: str = "claude-3-5-haiku-20241022",
    max_tokens: int = 2048,
) -> str:
    """
    Call the Anthropic Messages API with production-grade status-code handling.

    Retries on 429 (rate limit), 529 (API overloaded), and 5xx (transient).
    Raises typed exceptions for 401/403 (auth) and 4xx (bad request).
    """
    url = "https://api.anthropic.com/v1/messages"
    headers = {
        "x-api-key": api_key,
        "anthropic-version": "2023-06-01",
        "Content-Type": "application/json",
    }
    payload = {
        "model": model,
        "max_tokens": max_tokens,
        "messages": messages,
    }
    retryable = {429, 500, 529}

    for attempt in range(6):
        resp = httpx.post(url, headers=headers, json=payload, timeout=120.0)

        if resp.status_code == 200:
            return resp.json()["content"][0]["text"]

        if resp.status_code in retryable and attempt < 5:
            # Honor Retry-After if present (Anthropic sends it on 429)
            delay = float(resp.headers.get("Retry-After", 2 ** attempt))
            time.sleep(delay)
            continue

        if resp.status_code == 401:
            raise PermissionError("Anthropic API key invalid or expired")
        if resp.status_code == 400:
            err = resp.json().get("error", {})
            raise ValueError(f"Bad request: {err.get('message', resp.text)}")
        if resp.status_code == 403:
            raise PermissionError("Request forbidden by Anthropic policy")

        resp.raise_for_status()

    raise RuntimeError("Exhausted all retry attempts")
